def solve(age_years, has_history, surgery_status, temperature_celsius, map_mmHg, heart_rate_bpm, respiratory_rate_bpm, fio2_percent, pao2_mmHg, aa_gradient_mmHg, arterial_ph, serum_sodium_mmol_per_l, serum_potassium_mmol_per_l, serum_creatinine_mg_per_100ml, renal_failure_status, hematocrit_percent, wbc_count_per_cubic_mm_10_3, gcs_score):
    # Step 1: calculate_age_score
    if age_years <= 44:
        age_points = 0
    elif 45 <= age_years <= 54:
        age_points = 2
    elif 55 <= age_years <= 64:
        age_points = 3
    elif 65 <= age_years <= 74:
        age_points = 5
    else:  # age_years >= 75
        age_points = 6
    yield {
        "step_name": "calculate_age_score",
        "step_description": "Map age in years to APACHE II points: <=44=0, 45-54=2, 55-64=3, 65-74=5, >=75=6",
        "step_result": age_points,
        "unit": None
    }

    # Step 2: calculate_history_score
    if has_history:
        if surgery_status in ['nonoperative', 'emergency_postoperative']:
            history_points = 5
        elif surgery_status == 'elective_postoperative':
            history_points = 2
        else:
            history_points = 0  # default if surgery_status is unexpected
    else:
        history_points = 0
    yield {
        "step_name": "calculate_history_score",
        "step_description": "Calculate points for history of severe organ insufficiency or immunocompromised status based on surgery status",
        "step_result": history_points,
        "unit": None
    }

    # Step 3: calculate_temperature_score
    if temperature_celsius >= 41:
        temp_points = 4
    elif 39 <= temperature_celsius < 41:
        temp_points = 3
    elif 38.5 <= temperature_celsius < 39:
        temp_points = 1
    elif 36 <= temperature_celsius < 38.5:
        temp_points = 0
    elif 34 <= temperature_celsius < 36:
        temp_points = 1
    elif 32 <= temperature_celsius < 34:
        temp_points = 2
    elif 30 <= temperature_celsius < 32:
        temp_points = 3
    else:  # temperature_celsius < 30
        temp_points = 4
    yield {
        "step_name": "calculate_temperature_score",
        "step_description": "Map rectal temperature to APACHE II points",
        "step_result": temp_points,
        "unit": None
    }

    # Step 4: calculate_map_score
    if map_mmHg >= 160:
        map_points = 4
    elif 130 <= map_mmHg < 160:
        map_points = 3
    elif 110 <= map_mmHg < 130:
        map_points = 2
    elif 70 <= map_mmHg < 110:
        map_points = 0
    elif 50 <= map_mmHg < 70:
        map_points = 2
    elif 40 <= map_mmHg < 50:
        map_points = 3
    else:  # map_mmHg < 40
        map_points = 4
    yield {
        "step_name": "calculate_map_score",
        "step_description": "Map mean arterial pressure to APACHE II points",
        "step_result": map_points,
        "unit": None
    }

    # Step 5: calculate_heart_rate_score
    if heart_rate_bpm >= 180:
        hr_points = 4
    elif 140 <= heart_rate_bpm < 180:
        hr_points = 3
    elif 110 <= heart_rate_bpm < 140:
        hr_points = 2
    elif 70 <= heart_rate_bpm < 110:
        hr_points = 0
    elif 55 <= heart_rate_bpm < 70:
        hr_points = 2
    elif 40 <= heart_rate_bpm < 55:
        hr_points = 3
    else:  # heart_rate_bpm < 40
        hr_points = 4
    yield {
        "step_name": "calculate_heart_rate_score",
        "step_description": "Map heart rate to APACHE II points",
        "step_result": hr_points,
        "unit": None
    }

    # Step 6: calculate_respiratory_rate_score
    if respiratory_rate_bpm >= 50:
        rr_points = 4
    elif 35 <= respiratory_rate_bpm < 50:
        rr_points = 3
    elif 25 <= respiratory_rate_bpm < 35:
        rr_points = 1
    elif 12 <= respiratory_rate_bpm < 25:
        rr_points = 0
    elif 10 <= respiratory_rate_bpm < 12:
        rr_points = 1
    elif 6 <= respiratory_rate_bpm < 10:
        rr_points = 2
    else:  # respiratory_rate_bpm < 6
        rr_points = 4
    yield {
        "step_name": "calculate_respiratory_rate_score",
        "step_description": "Map respiratory rate to APACHE II points",
        "step_result": rr_points,
        "unit": None
    }

    # Step 7: calculate_oxygenation_score
    if fio2_percent >= 50:
        # Use Aa gradient
        if aa_gradient_mmHg >= 350:
            oxygenation_points = 4
        elif 200 <= aa_gradient_mmHg < 350:
            oxygenation_points = 2
        elif aa_gradient_mmHg < 200:
            oxygenation_points = 1
        else:
            oxygenation_points = 0  # fallback, should not reach
    else:
        # FiO2 < 50%, use PaO2
        if pao2_mmHg < 55:
            oxygenation_points = 4
        elif 55 <= pao2_mmHg <= 60:
            oxygenation_points = 3
        elif 61 <= pao2_mmHg <= 70:
            oxygenation_points = 1
        else:  # pao2_mmHg > 70
            oxygenation_points = 0
    yield {
        "step_name": "calculate_oxygenation_score",
        "step_description": "Calculate oxygenation points based on FiO2 and either PaO2 or Aa gradient",
        "step_result": oxygenation_points,
        "unit": None
    }

    # Step 8: calculate_ph_score
    if arterial_ph >= 7.7:
        ph_points = 4
    elif 7.60 <= arterial_ph < 7.70:
        ph_points = 3
    elif 7.50 <= arterial_ph < 7.60:
        ph_points = 1
    elif 7.33 <= arterial_ph < 7.50:
        ph_points = 0
    elif 7.25 <= arterial_ph < 7.33:
        ph_points = 2
    elif 7.15 <= arterial_ph < 7.25:
        ph_points = 3
    else:  # arterial_ph < 7.15
        ph_points = 4
    yield {
        "step_name": "calculate_ph_score",
        "step_description": "Map arterial pH to APACHE II points",
        "step_result": ph_points,
        "unit": None
    }

    # Step 9: calculate_sodium_score
    if serum_sodium_mmol_per_l >= 180:
        sodium_points = 4
    elif 160 <= serum_sodium_mmol_per_l < 180:
        sodium_points = 3
    elif 155 <= serum_sodium_mmol_per_l < 160:
        sodium_points = 2
    elif 150 <= serum_sodium_mmol_per_l < 155:
        sodium_points = 1
    elif 130 <= serum_sodium_mmol_per_l < 150:
        sodium_points = 0
    elif 120 <= serum_sodium_mmol_per_l < 130:
        sodium_points = 2
    elif 111 <= serum_sodium_mmol_per_l < 120:
        sodium_points = 3
    else:  # serum_sodium_mmol_per_l < 111
        sodium_points = 4
    yield {
        "step_name": "calculate_sodium_score",
        "step_description": "Map serum sodium to APACHE II points",
        "step_result": sodium_points,
        "unit": None
    }

    # Step 10: calculate_potassium_score
    if serum_potassium_mmol_per_l >= 7.0:
        potassium_points = 4
    elif 6.0 <= serum_potassium_mmol_per_l < 7.0:
        potassium_points = 3
    elif 5.5 <= serum_potassium_mmol_per_l < 6.0:
        potassium_points = 1
    elif 3.5 <= serum_potassium_mmol_per_l < 5.5:
        potassium_points = 0
    elif 3.0 <= serum_potassium_mmol_per_l < 3.5:
        potassium_points = 1
    elif 2.5 <= serum_potassium_mmol_per_l < 3.0:
        potassium_points = 2
    else:  # serum_potassium_mmol_per_l < 2.5
        potassium_points = 4
    yield {
        "step_name": "calculate_potassium_score",
        "step_description": "Map serum potassium to APACHE II points",
        "step_result": potassium_points,
        "unit": None
    }

    # Step 11: calculate_creatinine_score
    if renal_failure_status == 'acute':
        if serum_creatinine_mg_per_100ml >= 3.5:
            creatinine_points = 8
        elif 2.0 <= serum_creatinine_mg_per_100ml < 3.5:
            creatinine_points = 6
        elif 1.5 <= serum_creatinine_mg_per_100ml < 2.0:
            creatinine_points = 4
        else:
            creatinine_points = 0
    elif renal_failure_status == 'chronic':
        if serum_creatinine_mg_per_100ml >= 3.5:
            creatinine_points = 4
        elif 2.0 <= serum_creatinine_mg_per_100ml < 3.5:
            creatinine_points = 3
        elif 1.5 <= serum_creatinine_mg_per_100ml < 2.0:
            creatinine_points = 2
        else:
            creatinine_points = 0
    else:  # 'none' or other
        if 0.6 <= serum_creatinine_mg_per_100ml < 1.5:
            creatinine_points = 0
        elif serum_creatinine_mg_per_100ml < 0.6:
            creatinine_points = 2
        else:
            creatinine_points = 0
    yield {
        "step_name": "calculate_creatinine_score",
        "step_description": "Calculate serum creatinine points, considering renal failure status",
        "step_result": creatinine_points,
        "unit": None
    }

    # Step 12: calculate_hematocrit_score
    if hematocrit_percent >= 60:
        hematocrit_points = 4
    elif 50 <= hematocrit_percent < 60:
        hematocrit_points = 2
    elif 46 <= hematocrit_percent < 50:
        hematocrit_points = 1
    elif 30 <= hematocrit_percent < 46:
        hematocrit_points = 0
    elif 20 <= hematocrit_percent < 30:
        hematocrit_points = 2
    else:  # hematocrit_percent < 20
        hematocrit_points = 4
    yield {
        "step_name": "calculate_hematocrit_score",
        "step_description": "Map hematocrit to APACHE II points",
        "step_result": hematocrit_points,
        "unit": None
    }

    # Step 13: calculate_wbc_score
    if wbc_count_per_cubic_mm_10_3 >= 40:
        wbc_points = 4
    elif 20 <= wbc_count_per_cubic_mm_10_3 < 40:
        wbc_points = 2
    elif 15 <= wbc_count_per_cubic_mm_10_3 < 20:
        wbc_points = 1
    elif 3 <= wbc_count_per_cubic_mm_10_3 < 15:
        wbc_points = 0
    elif 1 <= wbc_count_per_cubic_mm_10_3 < 3:
        wbc_points = 2
    else:  # wbc_count_per_cubic_mm_10_3 < 1
        wbc_points = 4
    yield {
        "step_name": "calculate_wbc_score",
        "step_description": "Map white blood count to APACHE II points",
        "step_result": wbc_points,
        "unit": None
    }

    # Step 14: calculate_gcs_score
    gcs_points = 15 - gcs_score
    yield {
        "step_name": "calculate_gcs_score",
        "step_description": "Calculate Glasgow Coma Scale points (15 - GCS score)",
        "step_result": gcs_points,
        "unit": None
    }

    # Step 15: calculate_total_apache_ii
    apache_total = (age_points + history_points + temp_points + map_points + hr_points + rr_points +
                    oxygenation_points + ph_points + sodium_points + potassium_points + creatinine_points +
                    hematocrit_points + wbc_points + gcs_points)
    # No yield here as this is the final step; return directly
    return apache_total
